yaml:
id: no-flat-lifecycle-event
language: kotlin
severity: error
# A top-level `data class …Event` MUST be a subtype of the sealed `AgentEvent`
# hierarchy (have a `: AgentEvent()` supertype), never a free-floating flat
# struct dispatched via nullable callbacks. Activated with the AgentEvent redesign.
rule:
  all:
    - kind: class_declaration
    - inside: { kind: source_file }
    - has: { kind: type_identifier, regex: 'Event$', stopBy: neighbor }
    - has: { kind: modifiers, has: { kind: class_modifier, regex: 'data' } }
    - not: { has: { kind: delegation_specifier, stopBy: neighbor } }

goodExample:
public sealed class AgentEvent {
    public data class Foo(val x: Int) : AgentEvent()
}

